import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Using StringBuilder to dynamically allocate memory for the buffer
        StringBuilder buffer = new StringBuilder();

        // Copy user input into the buffer
        for (int i = 0; i < Math.min(name.length(), 10); i++) {
            buffer.append(name.charAt(i));
        }

        // Accessing the buffer safely without overflowing
        System.out.println("Welcome, " + buffer.toString());
    }
}

### Explanation:
취약유형: Buffer Overflow
